import "./FormStyles.css";

import React from 'react'

const Form = () => {
  return (
    <div className="form">
        <form>
            <label>Your Name</label>
            <inout type="text"></inout>

            <label>Email</label>
            <inout type="email"></inout>

            <label>Subject</label>
            <inout type="text"></inout>

            <label>Message</label>
            <textarea rows="6" placeholder="Type your message here" />

                <button className="btm">Submit</button>
        </form>

    </div>
  )
}



export default Form;
